import React, { useState } from "react";
import axios from "axios";

function AIChatbot() {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function getReply() {
    if (!question.trim()) {
      alert("Please enter a question");
      return;
    }

    try {
      setLoading(true);
      setError("");
      setAnswer("");

      const res = await axios.post("http://localhost:5000/api/chat", {
        question,
      });

      setAnswer(res.data.answer);
    } catch (err) {
      console.error(err);
      setError("AI response could not be loaded. Check backend/API key.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="card">
      <h3>AI Fitness Chatbot</h3>

      <input
        type="text"
        placeholder="Ask any fitness question..."
        value={question}
        onChange={(e) => setQuestion(e.target.value)}
      />

      <button onClick={getReply}>
        {loading ? "Thinking..." : "Ask AI"}
      </button>

      {error && <div className="advice-box">{error}</div>}

      {answer && <div className="advice-box">{answer}</div>}
    </div>
  );
}

export default AIChatbot;
